mapper.select:
SELECT u.id, u.username, u.nickname, u.email, u.phone, u.gender, u.birthdate, u.icon_url AS iconUrl, u.role, u.social_type AS socialType, u.status, u.suspend_until AS suspendUntil, u.created_at AS createdAt, /* 작성 리뷰 수 (삭제된 리뷰 제외) */ (SELECT COUNT(*) FROM reviews r WHERE r.user_id = u.id AND r.deleted_at IS NULL) AS reviewCount, /* 신고 받은 수 (해당 회원의 리뷰가 신고된 건수) */ (SELECT COUNT(*) FROM reports rp WHERE rp.target_type = 'REVIEW' AND rp.target_id IN ( SELECT r2.id FROM reviews r2 WHERE r2.user_id = u.id )) AS reportCount FROM users u
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') )
AND u.status = #{status}
ORDER BY u.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM users u
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') )
AND u.status = #{status}

mapper.update:
UPDATE users
SET status = #{status},
suspend_until = #{suspendUntil}
WHERE id = #{id}

mapper.select:
SELECT rp.id, rp.reporter_id AS reporterId, reporter.nickname AS reporterNickname, rp.target_type AS targetType, rp.target_id AS targetId, CASE WHEN rp.target_type = 'REVIEW' THEN LEFT(rev.content, 50) WHEN rp.target_type = 'TOILET' THEN tlt.name END AS targetName, CASE WHEN rp.target_type = 'REVIEW' THEN rev_user.nickname END AS targetWriter, rp.reason, rp.status, rp.admin_note AS adminNote, rp.created_at AS createdAt, rp.processed_at AS processedAt FROM reports rp /* 신고자 정보 */ JOIN users reporter ON rp.reporter_id = reporter.id /* 리뷰 대상 (target_type='REVIEW'일 때만 매칭) */ LEFT JOIN reviews rev ON rp.target_type = 'REVIEW' AND rp.target_id = rev.id LEFT JOIN users rev_user ON rev.user_id = rev_user.id /* 화장실 대상 (target_type='TOILET'일 때만 매칭) */ LEFT JOIN toilets tlt ON rp.target_type = 'TOILET' AND rp.target_id = tlt.id
AND rp.status = #{status}
AND rp.target_type = #{targetType}
ORDER BY CASE WHEN rp.status = 'PENDING' THEN 0 ELSE 1 END, rp.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM reports rp


        AND rp.status = #{status}


        AND rp.target_type = #{targetType}

SELECT t.id, t.name, t.address, t.latitude, t.longitude, t.open_hours AS openHours, t.is_24hours AS is24hours, t.is_wheelchair AS isWheelchair, t.has_paper AS hasPaper, t.has_soap AS hasSoap, t.has_sanitary AS hasSanitary, t.has_diaper AS hasDiaper, t.toilet_type AS toiletType, t.has_emergency AS hasEmergency, t.source, t.status, t.by_user_id AS byUserId, u.nickname AS byUserNickname, t.created_at AS createdAt FROM toilets t LEFT JOIN users u ON t.by_user_id = u.id WHERE t.deleted_at IS NULL
AND t.status = #{status}
ORDER BY CASE WHEN t.status = 'PENDING' THEN 0 ELSE 1 END, t.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT i.id, i.writer_id AS writerId, writer.nickname AS writerNickname, writer.email AS writerEmail, i.admin_id AS adminId, admin_user.nickname AS adminNickname, i.title, i.content, i.status, i.answer, i.answered_at AS answeredAt, i.created_at AS createdAt FROM inquiries i JOIN users writer ON i.writer_id = writer.id LEFT JOIN users admin_user ON i.admin_id = admin_user.id WHERE i.deleted_at IS NULL
AND i.status = #{status}
AND ( i.title LIKE CONCAT('%', #{keyword}, '%') OR i.content LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY CASE WHEN i.status = 'WAITING' THEN 0 ELSE 1 END, i.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM inquiries i WHERE i.deleted_at IS NULL
AND i.status = #{status}
AND ( i.title LIKE CONCAT('%', #{keyword}, '%') OR i.content LIKE CONCAT('%', #{keyword}, '%') )
